// ============================================================
// WF-04 [1.5] Normalize Binary — v1.2
// Run mode: Once for Each Item
// Cherry-picked from Invoices_11 (legacy workflow).
//
// Цель: унифицировать входной бинарник под стандартный ключ 'file',
//       независимо от того, как его назвала предыдущая нода.
//
// Поддерживает 2 контракта входа:
//   A) BINARY  — $input.item.binary.* уже существует. Ищем первый
//                ключ с поддерживаемым MIME (часто это 'data', 'file',
//                'attachment_0' и т.п.)
//   B) BASE64  — $json.fileBase64 + $json.mimeType (ручной тест)
//
// Выход: item.binary.file = {data, mimeType, fileName}
//        + json обогащается _binaryKey, _mimeType, _origFileName
// ============================================================

const item = $input.item;
const itemJson = item.json || {};
const itemBinary = item.binary || {};

const ALLOWED_MIME = [
  'application/pdf',
  'image/jpeg', 'image/jpg', 'image/png', 'image/webp', 'image/gif', 'image/tiff',
  'image/heic', 'image/heif'
];

// --- Контракт A: уже есть binary ---
const existingKey = Object.keys(itemBinary).find(k => {
  const mime = itemBinary[k]?.mimeType || '';
  return ALLOWED_MIME.some(a => mime.includes(a));
});

if (existingKey) {
  const fileObj = itemBinary[existingKey];
  return {
    json: {
      ...itemJson,
      _binaryKey: 'file',
      _mimeType: fileObj.mimeType || 'application/pdf',
      _origFileName: fileObj.fileName || ''
    },
    binary: { file: fileObj }
  };
}

// --- Контракт B: base64 в json ---
if (itemJson.fileBase64) {
  const mime = itemJson.mimeType || 'application/pdf';
  const buffer = Buffer.from(itemJson.fileBase64, 'base64');
  const origName = itemJson.originalFileName || 'upload.bin';
  return {
    json: {
      ...itemJson,
      _binaryKey: 'file',
      _mimeType: mime,
      _origFileName: origName
    },
    binary: {
      file: await this.helpers.prepareBinaryData(buffer, origName, mime)
    }
  };
}

// --- Ничего не пришло ---
throw new Error(
  'WF-04: no usable file data. Neither binary (with allowed MIME) ' +
  'nor json.fileBase64. ' +
  'Binary keys: [' + Object.keys(itemBinary).join(',') + '], ' +
  'Binary MIMEs: [' + Object.keys(itemBinary).map(k => itemBinary[k]?.mimeType || '?').join(',') + '], ' +
  'JSON keys: [' + Object.keys(itemJson).join(',') + ']'
);

// ============================================================
// WF-04 [2] Generate Filename — v1.2
// Run mode: Once for Each Item
// ============================================================

const item = $input.item;
const itemJson = item.json || {};
const itemBinary = item.binary || {};
const fields = itemJson.fields || itemJson;

const translitMap = {
  'а':'a','б':'b','в':'v','г':'g','д':'d','е':'e','ё':'yo','ж':'zh',
  'з':'z','и':'i','й':'j','к':'k','л':'l','м':'m','н':'n','о':'o',
  'п':'p','р':'r','с':'s','т':'t','у':'u','ф':'f','х':'h','ц':'ts',
  'ч':'ch','ш':'sh','щ':'sch','ъ':'','ы':'y','ь':'','э':'e','ю':'yu','я':'ya',
  'А':'A','Б':'B','В':'V','Г':'G','Д':'D','Е':'E','Ж':'Zh','З':'Z',
  'И':'I','К':'K','Л':'L','М':'M','Н':'N','О':'O','П':'P','Р':'R',
  'С':'S','Т':'T','У':'U','Ф':'F','Х':'H','Ц':'Ts','Ч':'Ch','Ш':'Sh',
  'Щ':'Sch','Ъ':'','Ы':'Y','Ь':'','Э':'E','Ю':'Yu','Я':'Ya'
};

function translit(str) {
  return (str || 'unknown')
    .split('')
    .map(c => translitMap[c] !== undefined ? translitMap[c] : c)
    .join('')
    .toLowerCase()
    .replace(/[^a-z0-9_\-\.]/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_|_$/g, '');
}

const resolvedMime = itemJson._mimeType || 'application/pdf';

let year, month;
const docDate = fields.docDate || '';
const dateParts = docDate.split('.');
if (dateParts.length === 3 && dateParts[2] && dateParts[1]) {
  month = dateParts[1].padStart(2, '0');
  year = dateParts[2];
} else {
  const now = new Date();
  month = String(now.getMonth() + 1).padStart(2, '0');
  year = String(now.getFullYear());
}
const yearMonth = `${year}.${month}`;

const counterpartySlug = translit(fields.counterparty || 'unknown').slice(0, 30) || 'unknown';
const rawAmount = String(fields.rawAmount || fields.amount || '0').replace(/[^0-9.]/g, '') || '0';

let ext = 'pdf';
if (resolvedMime.includes('png')) ext = 'png';
else if (resolvedMime.includes('jpeg') || resolvedMime.includes('jpg')) ext = 'jpg';
else if (resolvedMime.includes('webp')) ext = 'webp';
else if (resolvedMime.includes('tiff')) ext = 'tif';
else if (resolvedMime.includes('gif')) ext = 'gif';
else if (resolvedMime.includes('pdf')) ext = 'pdf';

const fileName = `${yearMonth}_${counterpartySlug}_${rawAmount}.${ext}`;
const subFolder = fields.status === 'Поступление' ? 'income' : 'outcome';

const updatedBinary = itemBinary.file
  ? { file: { ...itemBinary.file, fileName, mimeType: resolvedMime } }
  : itemBinary;

return {
  json: {
    ...itemJson,
    fileName,
    yearMonth,
    subFolder,
    fileExt: ext,
    resolvedMime
  },
  binary: updatedBinary
};

const yearMonthFolderId = $json.id;
if (!yearMonthFolderId) {
  throw new Error('WF-04: failed to resolve year-month folder id');
}
const srcBinary = $('Generate Filename').item.binary;
return {
  json: { ...$json, yearMonthFolderId },
  binary: srcBinary
};

const subFolderId = $json.id;
if (!subFolderId) {
  throw new Error('WF-04: failed to resolve sub-folder id');
}
const srcBinary = $('Normalize Binary').item.binary;
const genJson = $('Generate Filename').item.json;
return {
  json: {
    ...$json,
    subFolderId,
    fileName: genJson.fileName,
    yearMonth: genJson.yearMonth,
    subFolder: genJson.subFolder,
    resolvedMime: genJson.resolvedMime
  },
  binary: srcBinary
};

// ============================================================
// WF-04 [Return Existing File] — v1.5
// Run mode: Once for Each Item
//
// Ветка дедупликации: файл уже есть в папке — возвращаем его URL.
// $json здесь = output от Check File Exists (Google Drive search),
// где id это корректный file id.
// ============================================================

const existing = $json;
const fileId = existing.id || '';
const webViewLink = existing.webViewLink
  || (fileId ? `https://drive.google.com/file/d/${fileId}/view?usp=drive_link` : '');

return {
  json: {
    driveUrl: webViewLink,
    driveFileId: fileId,
    fileName: existing.name || $('Set Sub Folder ID').item.json.fileName || '',
    deduplicated: true
  }
};

// ============================================================
// WF-04 [Build Return Payload] — v1.5
// Run mode: Once for Each Item
//
// Bugfix v1.5: берём file id/link строго из ноды Upload File.
// Предыдущая нода (Make File Readable) — share-операция, возвращает
// permission-объект { id: 'anyoneWithLink', type: 'anyone' } —
// это НЕ file id, из-за чего в URL попадал мусор.
// ============================================================

const upload = $('Upload File').item.json;
const fileId = upload.id || '';
const fileName = upload.name || $('Set Sub Folder ID').item.json.fileName || '';

// webViewLink приходит от Google Drive upload если ответ включает этот field.
// Фолбэк: собираем URL вручную с usp=drive_link для корректного UI-поведения.
const webViewLink = upload.webViewLink
  || (fileId ? `https://drive.google.com/file/d/${fileId}/view?usp=drive_link` : '');

return {
  json: {
    driveUrl: webViewLink,
    driveFileId: fileId,
    fileName: fileName,
    deduplicated: false
  }
};

// ============================================================
// WF-04 [Restore Binary] — v1.3
// Run mode: Once for Each Item
//
// Зачем: Google Drive search-ноды (Check File Exists и пр.) не
// пропускают binary через себя. Перед Upload File нужно его
// восстановить из Normalize Binary.
// ============================================================

const srcBinary = $('Normalize Binary').item.binary;
const ctx = $('Set Sub Folder ID').item.json;

if (!srcBinary || !srcBinary.file) {
  throw new Error('Restore Binary: no binary.file on Normalize Binary output');
}

return {
  json: {
    ...ctx,
    ...$json
  },
  binary: srcBinary
};
